131: void SPIFFEValidator::updateDigestForSessionId(bssl::ScopedEVP_MD_CTX& md,
132:                                                uint8_t hash_buffer[EVP_MAX_MD_SIZE],
133:                                                unsigned hash_length) {
134:   int rc;
135:   for (auto& ca : ca_certs_) {
136:     rc = X509_digest(ca.get(), EVP_sha256(), hash_buffer, &hash_length);
137:     RELEASE_ASSERT(rc == 1, Utility::getLastCryptoError().value_or(""));
138:     RELEASE_ASSERT(hash_length == SHA256_DIGEST_LENGTH,
139:                    fmt::format("invalid SHA256 hash length {}", hash_length));
140:     rc = EVP_DigestUpdate(md.get(), hash_buffer, hash_length);
141:     RELEASE_ASSERT(rc == 1, Utility::getLastCryptoError().value_or(""));
142:   }
143: }
